import React from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Box,
  Spacer
} from '@ggui-ai/design/primitives';

export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastItem[];
}

/**
 * WeatherCard Component
 * Displays current weather metrics and a 5-day forecast.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast
}: Props) {
  const tempUnit = unit === 'F' ? '°F' : '°C';
  const speedUnit = unit === 'F' ? 'mph' : 'km/h';

  // Helper to map condition string to a large display emoji if needed
  // though we mostly rely on props-provided strings/icons
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    return '⛅';
  };

  return (
    <Card 
      shadow="md" 
      radius="xl" 
      padding={0} 
      border={true}
    >
      <Box 
        padding={24} 
        background="var(--ggui-color-primary-50, #f0f9ff)"
        borderRadius="12px 12px 0 0"
      >
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={4}>
            <Heading level={3} color="var(--ggui-color-primary-900, #0c4a6e)">
              {city}
            </Heading>
            <Text 
              variant="bodySmall" 
              color="var(--ggui-color-primary-700, #0369a1)"
            >
              {new Date().toLocaleDateString(undefined, { 
                weekday: 'long', 
                month: 'short', 
                day: 'numeric' 
              })}
            </Text>
          </Stack>
          <Box>
            <Text 
              size="4xl" 
              style={{ fontSize: 'var(--ggui-font-size-4xl, 48px)', lineHeight: 1 }}
            >
              {getConditionEmoji(condition)}
            </Text>
          </Box>
        </Stack>

        <Spacer size={24} />

        <Stack direction="horizontal" align="end" gap={8}>
          <Text 
            size="4xl" 
            weight="bold" 
            color="var(--ggui-color-onSurface, #18181b)"
            style={{ fontSize: '64px', lineHeight: 1 }}
          >
            {Math.round(temperature)}
          </Text>
          <Box paddingY={8}>
            <Text 
              variant="bodyLarge" 
              weight="medium" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {tempUnit}
            </Text>
          </Box>
          <Spacer size="flex" />
          <Box paddingY={8}>
            <Text 
              variant="bodyLarge" 
              weight="semibold" 
              color="var(--ggui-color-primary-800, #075985)"
            >
              {condition}
            </Text>
          </Box>
        </Stack>
      </Box>

      <Box padding={24} background="var(--ggui-color-surface, #ffffff)">
        <Stack direction="horizontal" justify="start" gap={32}>
          <Stack gap={2}>
            <Text 
              variant="overline" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text variant="body" weight="semibold">
              {humidity}%
            </Text>
          </Stack>
          <Stack gap={2}>
            <Text 
              variant="overline" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
            <Text variant="body" weight="semibold">
              {windSpeed} {speedUnit}
            </Text>
          </Stack>
        </Stack>

        <Divider margin={24} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Stack direction="horizontal" justify="between">
          {forecast.slice(0, 5).map((item, idx) => (
            <Stack key={idx} align="center" gap={8}>
              <Text 
                variant="caption" 
                weight="medium" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {item.day}
              </Text>
              <Text size="xl">
                {item.icon}
              </Text>
              <Stack gap={0} align="center">
                <Text variant="bodySmall" weight="bold">
                  {Math.round(item.high)}°
                </Text>
                <Text 
                  variant="caption" 
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {Math.round(item.low)}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Box>
    </Card>
  );
}
